    renderHook(() => useWebMCP())

    const searchCall = registerToolSpy.mock.calls.find(
      (call: unknown[]) => call[0] === 'search_colleges',
    )
    expect(searchCall).toBeDefined()

    const schema = searchCall![2] as Record<string, unknown>
    expect(schema.type).toBe('object')
    expect(schema.properties).toHaveProperty('filters')
    expect(schema.properties).toHaveProperty('limit')
    expect(schema.properties).toHaveProperty('offset')

    // Verify filter items describe typed value shapes (not plain string)
    const filters = (schema.properties as Record<string, Record<string, unknown>>).filters
    const items = filters.items as Record<string, unknown>
    const valueSchema = (items.properties as Record<string, Record<string, unknown>>).value
    expect(valueSchema).toHaveProperty('oneOf')
    expect(valueSchema).toHaveProperty('description')
    expect(valueSchema.description).toContain('Typed filter value')
  })","replace_all":false},"permission_updates":[]}}
